final:
module up_down_counter(
	input wire clk,
	input wire reset,
	input wire en,
	input wire up_down,
	output reg [2:0] count
);always @(posedge clk) begin
  wire _tap_clk = clk & {1{1'b1}};

		if (reset)
			count <= 3'b000;
		else if (en) begin
			if (up_down)
				count <= count + 1;
			else
				count <= count - 1;
		end
	end
endmodule
